  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { client, rpc } from "@/rpc/client";

import { clientColumnDefs } from "./client-list-view/columns";
import { clientColumnsConfig } from "./client-list-view/filters";

